// =========================================================================
// Title: sun with stars
// Author: nayk
// Link: https://www.shadertoy.com/view/tXKfz1
//
// Adaptation: Optimized for "Surfaces Explorer". 
// Fixed uninitialized variables (which cause errors on strict Desktop OpenGL).
// Adapted coordinates for mouse and dynamic resolution compatibility.
// =========================================================================

// just unrolled the loop, i guess we only need 3 layers
// to get some nice clouds :D
#define N(a) abs(dot(sin(iTime+.1*p.z+.3*p / a), vec3(a+a)))
#define NUM_LAYERS 12.
#define TAU 6.28318
#define PI 3.141592
#define Velocity .025 
#define StarGlow 0.025
#define StarSize 2.0
#define CanvasView 20.

float Star(vec2 uv, float flare){
    float d = length(uv);
    float m = sin(StarGlow*1.2)/d;  
    float rays = max(0., .5-abs(uv.x*uv.y*1000.)); 
    m += (rays*flare)*2.;
    m *= smoothstep(1., .1, d);
    return m;
}

float Hash21(vec2 p){
    p = fract(p*vec2(123.34, 456.21));
    p += dot(p, p+45.32);
    return fract(p.x*p.y);
}

vec3 StarLayer(vec2 uv){
    vec3 col = vec3(0);
    vec2 gv = fract(uv);
    vec2 id = floor(uv);
    for(int y=-1;y<=1;y++){
        for(int x=-1; x<=1; x++){
            vec2 offs = vec2(x,y);
            float n = Hash21(id+offs);
            float size = fract(n);
            float star = Star(gv-offs-vec2(n, fract(n*34.))+.5, smoothstep(.1,.9,size)*.46);
            vec3 color = sin(vec3(.2,.3,.9)*fract(n*2345.2)*TAU)*.25+.75;
            color = color*vec3(.9,.59,.9+size);
            star *= sin(iTime*.6+n*TAU)*.5+.5;
            col += star*size*color;
        }
    }
    return col;
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    // Inizializzazione rigorosa per C++ OpenGL Core
    vec4 o = vec4(0.0);
    float i = 0.0, s = 0.0;
    vec3 p = vec3(0.0);
    vec3 r = iResolution;   

    vec4 o2 = vec4(0.0);
    vec2 F = fragCoord;

    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;
    vec2 M = vec2(0.0);

    float t = iTime * 0.0; 
    vec3 col = vec3(0.0);  
    for(float j = 0.0; j < 1.0; j += 1.0 / NUM_LAYERS){
        float depth = fract(j + t);
        float scale = mix(CanvasView, 0.5, depth);
        float fade = depth * smoothstep(1.0, 0.9, depth);
        col += StarLayer(uv * scale + j * 453.2 - iTime * 0.05 + M) * fade;
    }   

    vec2 u = (fragCoord + fragCoord - r.xy) / r.y;

    for(o *= i; i++ < 1e2; ) {
        p += vec3(u * s, s);
        s = 6.0 + (p.y);
        s -= N(0.08);
        s -= N(0.2);
        s -= N(0.6);
        s = 0.1 + abs(s) * 0.2;
        o += vec4(4.0, 2.0, 1.0, 0.0) / s;
    }

    // Taglio bordi
    o *= smoothstep(0.8, 0.75, abs(u.y));

    vec2 R = iResolution.xy; 

    // Ciclo frattale principale (Variabili interne rinominate per sicurezza)
    for(float d, t2 = -iTime * 0.005, k = 0.0; k > -1.0; k -= 0.06 ) {           
        d = fract( k - 3.0 * t2 );                                          
        vec4 c = vec4( (F - R * 0.5) / R.y * d, k, 0.0 ) * 28.0;             
        for (int j=0 ; j++ < 27; ) {                                       
            c.xzyw = abs( c / dot(c,c)                                      
                    - vec4( 7.0 - 0.2 * sin(t2), 6.3, 0.7, 1.0 - cos(t2 / 0.8) ) / 7.0 ); 
        }
        o2 -= c * c.yzww * d-- * d / vec4(3.0, 5.0, 1.0, 1.0);                     
    }
    o += o2;

    o = tanh(o / 2e3 / length(u));

    // Creiamo una maschera morbida per le stelle
    float starMask = smoothstep(-0.4, 0.1, u.y);

    // Aggiungiamo morbidamente le stelle al risultato
    o.rgb += col * starMask * o2.xyz * 12.0;

    fragColor = vec4(o.rgb, 1.0);
}

